// Internal — alerts persistence
// ---------------------------------------------------------------------------

function saveAlerts(alerts: readonly Alert[]): void {
  const path = alertsPath()
  mkdirSync(dirname(path), { recursive: true })
  writeFileSync(path, JSON.stringify(alerts, null, 2) + '\n', 'utf-8')
}

